-- ============================================================
-- MercuryGate Carriers + Users Reference Tables
-- Run in Supabase Studio at http://127.0.0.1:54323
-- ============================================================

CREATE TABLE IF NOT EXISTS mg_carriers (
  id                  bigserial PRIMARY KEY,
  name                text NOT NULL,
  mc_number           text,
  scac                text,
  modes               text,
  early_ins_exp       text,
  equipment           text,
  loc_city            text,
  loc_state           text,
  loc_type            text,
  cargo_ins_amt       text,
  cargo_ins_exp       text,
  general_ins_amt     text,
  general_ins_exp     text,
  liability_ins_amt   text,
  liability_ins_exp   text,
  created_at          timestamptz DEFAULT now(),
  UNIQUE(scac)
);

CREATE INDEX IF NOT EXISTS idx_mg_carriers_scac ON mg_carriers(scac);
CREATE INDEX IF NOT EXISTS idx_mg_carriers_name ON mg_carriers(name);
CREATE INDEX IF NOT EXISTS idx_mg_carriers_mc   ON mg_carriers(mc_number);

CREATE TABLE IF NOT EXISTS mg_users (
  id                  bigserial PRIMARY KEY,
  owner               text,
  user_id             text,
  last_login          text,
  password_update     text,
  first_name          text,
  last_name           text,
  email               text,
  roles               text,
  lockout_status      text,
  created_at          timestamptz DEFAULT now(),
  UNIQUE(user_id)
);

CREATE INDEX IF NOT EXISTS idx_mg_users_owner  ON mg_users(owner);
CREATE INDEX IF NOT EXISTS idx_mg_users_email  ON mg_users(email);

-- Carriers (2984 rows)
ON CONFLICT (scac) DO NOTHING;

ON CONFLICT (scac) DO NOTHING;

ON CONFLICT (scac) DO NOTHING;

ON CONFLICT (scac) DO NOTHING;

ON CONFLICT (scac) DO NOTHING;

ON CONFLICT (scac) DO NOTHING;

-- Users (290 rows)
ON CONFLICT (user_id) DO NOTHING;

-- Update mg_tms view to include carrier details
DROP VIEW IF EXISTS mg_tms;

CREATE OR REPLACE VIEW mg_tms AS
SELECT
  d.*,
  e.name              AS customer_name,
  e.parent_name       AS customer_parent,
  e.enterprise_type   AS customer_type,
  c.name              AS carrier_full_name,
  c.mc_number         AS carrier_mc,
  c.loc_city          AS carrier_city,
  c.loc_state         AS carrier_state,
  c.modes             AS carrier_modes
FROM mg_data d
LEFT JOIN mg_enterprise e ON e.account_number = d.owner
LEFT JOIN mg_carriers   c ON c.scac = d.carrier_scac;

GRANT SELECT ON mg_carriers TO anon, authenticated;
GRANT SELECT ON mg_users    TO anon, authenticated;
GRANT SELECT ON mg_tms      TO anon, authenticated;
GRANT SELECT ON mg_enterprise TO anon, authenticated;

NOTIFY pgrst, 'reload schema';
